#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int time1[2], time2[2], dist;
        scanf("%d:%d", &time1[0], &time1[1]);
        scanf("%d:%d", &time2[0], &time2[1]);
        scanf("%d", &dist);
        int time1Total = time1[0] * 60 + time1[1];
        int time2Total = time2[0] * 60 + time2[1];
        int timeDiff = time1Total - time2Total;
        double plan1 = timeDiff + 2 * dist;
        double plan2 = dist + (dist - (timeDiff / 2.0));
        printf("%.1f %.1f\n", plan1, plan2);
    }
    return 0;
}

