code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String[] time1 = sc.next().split(":");
            String[] time2 = sc.next().split(":");
            int dist = sc.nextInt();
            int time1Total = Integer.parseInt(time1[0]) * 60 + Integer.parseInt(time1[1]);
            int time2Total = Integer.parseInt(time2[0]) * 60 + Integer.parseInt(time2[1]);
            int timeDiff = time1Total - time2Total;
            double plan1 = timeDiff + 2 * dist;
            double plan2 = dist + (dist - (timeDiff / 2.0));
            System.out.printf("%.1f %.1f\n", plan1, plan2);
        }
    }
}

