const lines = require('fs').readFileSync(0,'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const time1 = readline().split(":");
    const time2 = readline().split(":");
    const dist = parseInt(readline());
    const time1Total = parseInt(time1[0]) * 60 + parseInt(time1[1]);
    const time2Total = parseInt(time2[0]) * 60 + parseInt(time2[1]);
    const timeDiff = time1Total - time2Total;
    const plan1 = timeDiff + 2 * dist;
    const plan2 = dist + (dist - (timeDiff / 2.0));
    console.log(plan1.toFixed(1) + " " + plan2.toFixed(1));
}
